class Solution {
    public int rob(int[] nums) {
        if (nums.length == 1) return nums[0];
        return Math.max(robRange(nums, 0, nums.length - 2), robRange(nums, 1, nums.length - 1));
    }

    private int robRange(int[] nums, int start, int end) {
        int prev = 0, curr = 0;
        for (int i = start; i <= end; i++) {
            int next = Math.max(curr, prev + nums[i]);
            prev = curr;
            curr = next;
        }
        return curr;
    }
}

class Solution {
    public int rob(int[] nums) {
        if (nums.length == 1) return nums[0];
        return Math.max(robMemo(nums, 0, nums.length - 2), robMemo(nums, 1, nums.length - 1));
    }

    private int robMemo(int[] nums, int start, int end) {
        int[] memo = new int[nums.length];
        Arrays.fill(memo, -1);
        return helper(nums, start, end, memo);
    }

    private int helper(int[] nums, int i, int end, int[] memo) {
        if (i > end) return 0;
        if (memo[i] != -1) return memo[i];
        int rob = nums[i] + helper(nums, i + 2, end, memo);
        int skip = helper(nums, i + 1, end, memo);
        memo[i] = Math.max(rob, skip);
        return memo[i];
    }
}

